import { 
  useLocation, 
  useNavigate, 
  useParams, 
  type Location, 
  type NavigateFunction, 
  type Params 
} from 'react-router';
import { ComponentType } from 'react';

interface RouterProps {
  location: Location;
  params: Params;
  navigate: NavigateFunction;
}

// Define proper types for the component and its props
export const useRouter = <P extends object>(
  Component: ComponentType<P & RouterProps>
) => {
  const ComponentWithRouterProp = (props: P) => {
    const location = useLocation();
    const navigate = useNavigate();
    const params = useParams();

    return (
      <Component
        {...props}
        location={location}
        params={params}
        navigate={navigate}
      />
    );
  };

  // Add display name for better debugging
  ComponentWithRouterProp.displayName = `WithRouter(${Component.displayName || Component.name || 'Component'})`;

  return ComponentWithRouterProp;
};
```

