const AnimatedRoutes = () => {
  const location = useLocation();

  return (
    <TransitionGroup>
      <CSSTransition
        key={location.key}
        timeout={{
          enter: 400,
          exit: 400,
        }}
        classNames="page"
        unmountOnExit
      >
        <Routes location={location}>
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/resume" element={<Resume />} />
          <Route path="/contact" element={<ContactUs />} />
          <Route path="*" element={<Home />} />
        </Routes>
      </CSSTransition>
    </TransitionGroup>
  );
};

function AppRoutes() {
  return (
    <div className="s_c">
      <AnimatedRoutes />
    </div>
  );
}

export default AppRoutes;
```

Key changes made:
1. Removed the unused `useRouter` hook and imported `useLocation` directly from 'react-router-dom'
2. Removed the unnecessary `exact` prop from the root route (it's no longer needed in React Router v6)
3. Added React import
4. Changed the import from "react-router" to "react-router-dom" which is the correct package for web applications
5. Fixed the formatting for better readability

